+// Render HTML into a container with entrance animation
+function renderWithEntrance(containerId, html) {
+  const el = document.getElementById(containerId);
+  if (!el) return;
+  el.innerHTML = html;
+  el.classList.remove('result-enter');
+  void el.offsetWidth; // force reflow to restart animation
+  el.classList.add('result-enter');
+  // Spring animate with motion if available
+  if (motionLib) {
+    motionLib.animate(el, { opacity: [0.6, 1], transform: ['translateY(6px)', 'translateY(0)'] },
+      { type: 'spring', stiffness: 200, damping: 22 });
+  }
+}
